def get_memcache_client():
    """Create and return a Memcached client with retry logic."""
    base_client = Client(
        (app.config['MEMCACHED_HOST'], app.config['MEMCACHED_PORT']),
        serde=JsonSerde(),
        connect_timeout=5,
        timeout=3,
        no_delay=True,
        default_noreply=False
    )
    client = RetryingClient(
        base_client,
        attempts=3,
        retry_delay=0.1,
        retry_for=[MemcacheUnexpectedCloseError, ConnectionRefusedError, OSError]
    )
    return client


