class CacheManager:
    """Manages caching operations with Memcached."""

    def __init__(self, client):
        self.client = client

    def get(self, key):
        """Get a value from cache."""
        try:
            result = self.client.get(key)
            if result is not None:
                app.logger.debug(f"Cache HIT for key: {key}")
            else:
                app.logger.debug(f"Cache MISS for key: {key}")
            return result
        except Exception as e:
            app.logger.error(f"Cache GET error for key {key}: {e}")
            return None

    def set(self, key, value, ttl=None):
        """Set a value in cache with optional TTL."""
        if ttl is None:
            ttl = app.config['DEFAULT_CACHE_TTL']
        try:
            self.client.set(key, value, expire=ttl)
            app.logger.debug(f"Cache SET for key: {key} with TTL: {ttl}s")
            return True
        except Exception as e:
            app.logger.error(f"Cache SET error for key {key}: {e}")
            return False

    def delete(self, key):
        """Delete a value from cache."""
        try:
            self.client.delete(key)
            app.logger.debug(f"Cache DELETE for key: {key}")
            return True
        except Exception as e:
            app.logger.error(f"Cache DELETE error for key {key}: {e}")
            return False

    def invalidate_pattern(self, prefix):
        """
        Invalidate cache entries by tracking keys with a prefix.
        Since Memcached doesn't support pattern deletion natively,
        we maintain a set of keys per prefix.
        """
        try:
            tracked_keys = self.client.get(f"_keys_{prefix}")
            if tracked_keys and isinstance(tracked_keys, list):
                for key in tracked_keys:
                    self.client.delete(key)
                self.client.delete(f"_keys_{prefix}")
                app.logger.debug(f"Invalidated {len(tracked_keys)} keys with prefix: {prefix}")
            return True
        except Exception as e:
            app.logger.error(f"Cache invalidate_pattern error for prefix {prefix}: {e}")
            return False

    def track_key(self, prefix, key):
        """Track a cache key under a prefix for bulk invalidation."""
        try:
            tracked_keys = self.client.get(f"_keys_{prefix}") or []
            if key not in tracked_keys:
                tracked_keys.append(key)
                self.client.set(f"_keys_{prefix}", tracked_keys, expire=86400)  # 24h tracking
        except Exception as e:
            app.logger.error(f"Cache track_key error: {e}")

    def get_stats(self):
        """Get Memcached server statistics."""
        try:
            stats = self.client.stats()
            decoded_stats = {}
            for key, value in stats.items():
                k = key.decode('utf-8') if isinstance(key, bytes) else key
                v = value.decode('utf-8') if isinstance(value, bytes) else value
                decoded_stats[k] = v
            return decoded_stats
        except Exception as e:
            app.logger.error(f"Cache stats error: {e}")
            return {}

    def flush_all(self):
        """Flush all cache entries."""
        try:
            self.client.flush_all()
            app.logger.info("Cache flushed entirely")
            return True
        except Exception as e:
            app.logger.error(f"Cache flush error: {e}")
            return False


# Initialize cache manager
cache_manager = CacheManager(cache_client)


def generate_cache_key(*args, **kwargs):
    """Generate a consistent cache key from arguments."""
    key_data = json.dumps({'args': args, 'kwargs': kwargs}, sort_keys=True, default=str)
    return hashlib.md5(key_data.encode()).hexdigest()


def cached(ttl=None, prefix="default", key_func=None):
    """
    Decorator to cache function results in Memcached.
    
    Args:
        ttl: Time to live in seconds
        prefix: Cache key prefix for grouping
        key_func: Custom function to generate cache key
    """
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            if key_func:
                cache_key = f"{prefix}:{key_func(*args, **kwargs)}"
            else:
                cache_key = f"{prefix}:{func.__name__}:{generate_cache_key(*args, **kwargs)}"

            # Try to get from cache
            cached_result = cache_manager.get(cache_key)
            if cached_result is not None:
                return cached_result

            # Execute function and cache result
            result = func(*args, **kwargs)
            cache_manager.set(cache_key, result, ttl=ttl)
            cache_manager.track_key(prefix, cache_key)
            return result

        wrapper.cache_prefix = prefix
        wrapper.invalidate_cache = lambda: cache_manager.invalidate_pattern(prefix)
        return wrapper
    return decorator


def cache_response(ttl=None, prefix="api", key_func=None):
    """
    Decorator specifically for Flask route handlers to cache API responses.
    Uses request path and query parameters as cache key by default.
    """
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            if key_func:
                cache_key = f"{prefix}:{key_func()}"
            else:
                request_key = f"{request.path}:{request.query_string.decode('utf-8')}"
                cache_key = f"{prefix}:{func.__name__}:{hashlib.md5(request_key.encode()).hexdigest()}"

            # Try cache
            cached_result = cache_manager.get(cache_key)
            if cached_result is not None:
                response = jsonify(cached_result)
                response.headers['X-Cache'] = 'HIT'
                return response

            # Execute and cache
            result = func(*args, **kwargs)
            
            # Handle Flask response objects
            if hasattr(result, 'get_json'):
                response_data = result.get_json()
            elif isinstance(result, tuple):
                response_data = result[0] if isinstance(result[0], dict) else result
            elif isinstance(result, dict):
                response_data = result
            else:
                response_data = result

            cache_manager.set(cache_key, response_data, ttl=ttl)
            cache_manager.track_key(prefix, cache_key)

            response = jsonify(response_data)
            response.headers['X-Cache'] = 'MISS'
            return response

        wrapper.cache_prefix = prefix
        wrapper.invalidate_cache = lambda: cache_manager.invalidate_pattern(prefix)
        return wrapper
    return decorator


