@app.route('/health')
def health():
    """Health check including Memcached connectivity."""
    memcached_healthy = False
    try:
        cache_client.set('health_check', 'ok', expire=10)
        result = cache_client.get('health_check')
        memcached_healthy = result == 'ok'
    except Exception as e:
        app.logger.error(f"Health check failed: {e}")

    status = "healthy" if memcached_healthy else "degraded"
    status_code = 200 if memcached_healthy else 503

    return jsonify({
        "status": status,
        "memcached": "connected" if memcached_healthy else "disconnected",
        "timestamp": datetime.utcnow().isoformat()
    }), status_code


@app.route('/benchmark')
def benchmark():
    """
    Benchmark endpoint to demonstrate cache performance.
    Makes the same query twice - first uncached, then cached.
    """
    results = {}

    # Flush to ensure clean benchmark
    cache_manager.flush_all()

    # Uncached call
    start = time.time()
    _ = db.get_dashboard_stats()
    uncached_time = time.time() - start
    results['uncached_query_ms'] = round(uncached_time * 1000, 2)

    # Prime the cache
    start = time.time()
    _ = get_dashboard_stats_cached()
    first_cached_time = time.time() - start
    results['first_call_with_cache_ms'] = round(first_cached_time * 1000, 2)

    # Cached call
    start = time.time()
    _ = get_dashboard_stats_cached()
    cached_time = time.time() - start
    results['cached_query_ms'] = round(cached_time * 1000, 2)

    # Speedup
    if cached_time > 0:
        results['speedup_factor'] = round(uncached_time / cached_time, 1)
    else:
        results['speedup_factor'] = "∞"

    results['summary'] = (
        f"Uncached: {results['uncached_query_ms']}ms, "
        f"Cached: {results['cached_query_ms']}ms, "
        f"Speedup: {results['speedup_factor']}x"
    )

    return jsonify(results)


